import re

# Load data
mongo_file = 'var_function-call-17066351267170848336.json'
sql_data = locals()['var_function-call-10566155822468420405']

with open(mongo_file, 'r') as f:
    mongo_data = json.load(f)

# Create rating lookup
rating_map = {row['business_ref']: float(row['avg_rating']) for row in sql_data}

# US States
us_states = {
    'AL', 'AK', 'AZ', 'AR', 'CA', 'CO', 'CT', 'DE', 'FL', 'GA', 
    'HI', 'ID', 'IL', 'IN', 'IA', 'KS', 'KY', 'LA', 'ME', 'MD', 
    'MA', 'MI', 'MN', 'MS', 'MO', 'MT', 'NE', 'NV', 'NH', 'NJ', 
    'NM', 'NY', 'NC', 'ND', 'OH', 'OK', 'OR', 'PA', 'RI', 'SC', 
    'SD', 'TN', 'TX', 'UT', 'VT', 'VA', 'WA', 'WV', 'WI', 'WY', 'DC'
}

state_stats = {} # State -> {'count': 0, 'total_rating': 0.0}

for business in mongo_data:
    attrs = business.get('attributes')
    desc = business.get('description')
    b_id = business.get('business_id')

    # Check WiFi
    has_wifi = False
    if attrs and attrs != "None" and isinstance(attrs, dict):
        wifi_val = attrs.get('WiFi')
        if wifi_val:
            w_norm = str(wifi_val).lower().replace("u'", "'").replace("'", "").replace('"', '')
            if 'free' in w_norm or 'paid' in w_norm:
                has_wifi = True

    if has_wifi and desc:
        # Extract state using regex: comma, space, 2 caps
        # Find all matches, check if in us_states
        matches = re.findall(r",\s([A-Z]{2})", desc)
        found_state = None
        for m in matches:
            if m in us_states:
                found_state = m
                break # Take the first valid state found

        if found_state:
            ref_id = b_id.replace('businessid_', 'businessref_')
            rating = rating_map.get(ref_id)

            if rating is not None:
                if found_state not in state_stats:
                    state_stats[found_state] = {'count': 0, 'total_rating': 0.0}
                state_stats[found_state]['count'] += 1
                state_stats[found_state]['total_rating'] += rating

# Find best state
best_state = None
max_count = -1
avg_rating_of_best = 0.0

for st, stats in state_stats.items():
    if stats['count'] > max_count:
        max_count = stats['count']
        best_state = st
        avg_rating_of_best = stats['total_rating'] / stats['count']
    elif stats['count'] == max_count:
        # Tie
        pass

result = {
    "state": best_state,
    "count": max_count,
    "average_rating": avg_rating_of_best,
    "all_stats": state_stats
}

print("__RESULT__:")
print(json.dumps(result))
"}

